import { semverCompare } from '../../src/semver.mjs';
import test from 'node:test';
import assert from 'node:assert';
test('golden semver', () => {
  assert.strictEqual(semverCompare('10.0.0', '2.0.0'), 1);
  assert.strictEqual(semverCompare('2.0.0', '10.0.0'), -1);
  assert.strictEqual(semverCompare('1.2.3', '1.2.3'), 0);
  assert.strictEqual(semverCompare('1.2.0', '1.1.9'), 1);
  assert.strictEqual(semverCompare('1.0.1', '1.0.0'), 1);
});
